        </div>

      </div>
    </div>

    <!-- Footer on Left Side -->
    <div class="relative z-10 flex items-center justify-between text-xs text-slate-500 border-t border-slate-800/60 pt-6">
      <span>Consola Administrativa v1.0</span>
      <div class="flex gap-4">
        <span class="flex items-center gap-1.5"><span class="w-1.5 h-1.5 bg-emerald-500 rounded-full animate-pulse"></span> Servidor Activo</span>
      </div>
    </div>
  </div>

  <!-- Right Side: Structured Login Form -->
  <div class="w-full md:w-2/5 flex flex-col justify-between p-8 md:p-16 bg-white relative overflow-y-auto">

    <!-- Light-mode Grid overlay for visual consistency -->
    <div class="absolute inset-0 bg-[linear-gradient(to_right,#e2e8f080_1px,transparent_1px),linear-gradient(to_bottom,#e2e8f080_1px,transparent_1px)] bg-[size:30px_30px] opacity-40 pointer-events-none z-0"></div>

    <div></div> <!-- Spacing helper -->

    <!-- Main Container Card: Squared, Grid-Aligned -->
    <div class="w-full max-w-md mx-auto relative z-10 bg-white border border-slate-200 p-8 md:p-10 rounded-none shadow-[6px_6px_0px_0px_rgba(15,23,42,0.15)]">

      <!-- Top header -->
      <div class="mb-8">
        <h2 class="text-2xl font-black text-slate-900 tracking-tight font-label uppercase">
          ACCEDER AL CAMPUS
        </h2>
        <p class="text-slate-500 text-xs mt-1.5 leading-relaxed font-body">
          Introduce tus datos registrados para ingresar a la plataforma.
        </p>
      </div>

      <!-- Form -->
      <form [formGroup]="loginForm" (ngSubmit)="onSubmit()" class="space-y-5">

        <!-- Error alert message: Squared and bordered -->
        @if (errorMessage) {
          <div class="flex items-start gap-3 bg-red-50 border border-red-200 text-red-800 p-4 rounded-none text-xs font-semibold">
            <span class="material-symbols-outlined text-red-600 text-base mt-0.5">warning</span>
            <div class="flex-grow">
              <span class="block font-bold">Error al ingresar</span>
              <span class="block font-normal mt-0.5 text-red-600">{{ errorMessage }}</span>
            </div>
          </div>
        }

        <!-- Username Input: Squared -->
        <div>
          <label class="block font-label text-[10px] font-bold text-slate-700 mb-1.5 uppercase tracking-widest" for="email">
            Correo Electrónico
          </label>
          <div class="relative">
            <div class="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-slate-400">
              <span class="material-symbols-outlined text-lg">mail</span>
            </div>
            <input 
              formControlName="correo" 
              class="block w-full pl-10 pr-3 py-3 border border-slate-300 rounded-none bg-white text-slate-900 focus:outline-none focus:ring-1 focus:ring-primary focus:border-primary text-sm transition-all placeholder-slate-400" 
              id="email" 
              placeholder="correo@insteip.com" 
              type="email">
          </div>
          @if (loginForm.get('correo')?.hasError('required') && loginForm.get('correo')?.touched) {
            <p class="text-[11px] text-red-600 mt-1 flex items-center gap-1 font-medium">
              <span class="material-symbols-outlined text-[12px] font-bold">info</span>
              El correo es obligatorio.
            </p>
          }
          @if (loginForm.get('correo')?.hasError('email') && loginForm.get('correo')?.touched) {
            <p class="text-[11px] text-red-600 mt-1 flex items-center gap-1 font-medium">
              <span class="material-symbols-outlined text-[12px] font-bold">info</span>
              El formato de correo no es válido.
            </p>
          }
        </div>

        <!-- Password Input: Squared -->
        <div>
          <div class="flex items-center justify-between mb-1.5">
            <label class="block font-label text-[10px] font-bold text-slate-700 uppercase tracking-widest" for="password">
              Contraseña
            </label>
            <a (click)="openRecoveryModal(); $event.preventDefault()" class="text-[10px] text-primary hover:underline font-bold uppercase tracking-wider cursor-pointer">
              ¿La olvidaste?
            </a>
          </div>
          <div class="relative">
            <div class="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-slate-400">
              <span class="material-symbols-outlined text-lg">lock</span>
            </div>
            <input 
              formControlName="password" 
              [type]="hidePassword ? 'password' : 'text'" 
              class="block w-full pl-10 pr-10 py-3 border border-slate-300 rounded-none bg-white text-slate-900 focus:outline-none focus:ring-1 focus:ring-primary focus:border-primary text-sm transition-all" 
              id="password" 
              placeholder="••••••••">
            <button 
              type="button"
              (click)="hidePassword = !hidePassword"
              class="absolute inset-y-0 right-0 pr-3 flex items-center text-slate-400 hover:text-slate-600 transition-colors">
              <span class="material-symbols-outlined text-base">
                {{ hidePassword ? 'visibility' : 'visibility_off' }}
              </span>
            </button>
          </div>
          @if (loginForm.get('password')?.hasError('required') && loginForm.get('password')?.touched) {
            <p class="text-[11px] text-red-600 mt-1 flex items-center gap-1 font-medium">
              <span class="material-symbols-outlined text-[12px] font-bold">info</span>
              La contraseña es obligatoria.
            </p>
          }
        </div>

        <!-- Remember Me Checkbox -->
        <div class="flex items-center">
          <input 
            formControlName="rememberMe" 
            class="h-4.5 w-4.5 text-primary focus:ring-primary border-slate-300 rounded-none bg-white" 
            id="remember-me" 
            type="checkbox">
          <label class="ml-2 block text-xs text-slate-600 font-medium select-none" for="remember-me">
            Mantener sesión iniciada
          </label>
        </div>

        <!-- Submit Button: Squared with flat aesthetic -->
        <button 
          [disabled]="loginForm.invalid || isLoading" 
          class="w-full flex justify-center items-center gap-2 py-3.5 px-4 border border-transparent rounded-none text-xs font-bold text-white bg-slate-900 hover:bg-slate-800 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-slate-900 transition-all uppercase tracking-widest shadow-sm disabled:opacity-40 disabled:cursor-not-allowed" 
          type="submit">
          @if (isLoading) {
            <span class="animate-spin inline-block w-4 h-4 border-2 border-white border-t-transparent rounded-full"></span>
            Procesando...
          } @else {
            <span>Ingresar</span>
            <span class="material-symbols-outlined text-sm font-bold">arrow_forward</span>
          }
        </button>
      </form>

      <!-- Demo Credentials Selector (Highly Structured, Grid-Aligned) -->
      <div class="mt-8 pt-6 border-t border-slate-200">
        <span class="block text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-3 text-center">Acceso Rápido de Prueba</span>
        <div class="grid grid-cols-2 gap-3">
          <button 
            type="button" 
            (click)="autofill('admin')" 
            class="flex flex-col items-center justify-center p-3 border border-slate-200 hover:border-slate-400 hover:bg-slate-50 transition-all rounded-none text-center">
            <span class="material-symbols-outlined text-lg text-primary mb-1">admin_panel_settings</span>
            <span class="text-xs font-bold text-slate-800">Administrador</span>
            <span class="text-[9px] text-slate-500 mt-0.5">admin&#64;insteip.com</span>
          </button>
          <button 
            type="button" 
            (click)="autofill('student')" 
            class="flex flex-col items-center justify-center p-3 border border-slate-200 hover:border-slate-400 hover:bg-slate-50 transition-all rounded-none text-center">
            <span class="material-symbols-outlined text-lg text-[#bfab49] mb-1">school</span>
            <span class="text-xs font-bold text-slate-800">Estudiante</span>
            <span class="text-[9px] text-slate-500 mt-0.5">juan.perez&#64;insteip.com</span>
          </button>
        </div>
      </div>
    </div>

    <!-- Footer in Right Side -->
    <div class="w-full max-w-md mx-auto mt-8 text-center text-[10px] text-slate-400 relative z-10">
      <div class="flex justify-center gap-4 mb-2">
        <a class="hover:text-slate-600 transition-colors" href="#">Términos de servicio</a>
        <span>•</span>
        <a class="hover:text-slate-600 transition-colors" href="#">Políticas</a>
        <span>•</span>
        <a class="hover:text-slate-600 transition-colors" href="#">Soporte Técnico</a>
      </div>
      <p>© 2026 Instituto INSTEIP. Todos los derechos reservados.</p>
    </div>

  </div>

  <!-- Password Recovery Modal (Premium Glassmorphism & Brutalist Style) -->
  <div *ngIf="showRecoveryModal" class="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-50 flex items-center justify-center p-4">
    <div class="w-full max-w-md bg-white border border-slate-200 shadow-2xl rounded-none overflow-hidden relative">
      <!-- Modal Header -->
      <div class="px-6 py-4 border-b border-slate-200 bg-slate-50 flex items-center justify-between">
        <h3 class="text-xs font-black text-slate-900 uppercase tracking-widest">
          Recuperación de Contraseña
        </h3>
        <button (click)="closeRecoveryModal()" class="text-slate-400 hover:text-slate-600">
          <span class="material-symbols-outlined text-lg">close</span>
        </button>
      </div>

      <div class="p-6 space-y-4">
        <!-- Error message -->
        <div *ngIf="recoveryError" class="flex items-start gap-2 bg-red-50 border border-red-200 text-red-800 p-3 rounded-none text-[11px] font-semibold">
          <span class="material-symbols-outlined text-red-600 text-base">warning</span>
          <span>{{ recoveryError }}</span>
        </div>

        <!-- Success message -->
        <div *ngIf="recoveryMessage" class="flex items-start gap-2 bg-emerald-50 border border-emerald-200 text-emerald-800 p-3 rounded-none text-[11px] font-semibold">
          <span class="material-symbols-outlined text-emerald-600 text-base">check_circle</span>
          <span>{{ recoveryMessage }}</span>
        </div>

        <!-- STEP 1: Request code -->
        <div *ngIf="recoveryStep === 1" class="space-y-4">
          <p class="text-xs text-slate-500 leading-relaxed">
            Ingresa tu correo electrónico registrado. Si coincide con tu cuenta, te enviaremos un código de recuperación temporal de 6 dígitos.
          </p>
          <div>
            <label class="block font-label text-[10px] font-bold text-slate-700 mb-1.5 uppercase tracking-widest">Correo Electrónico</label>
            <input 
              [(ngModel)]="recoveryEmail" 
              type="email" 
              class="w-full px-3 py-2 border border-slate-300 bg-white text-slate-900 text-xs rounded-none focus:outline-none focus:ring-1 focus:ring-primary focus:border-primary"
              placeholder="correo@insteip.com">
          </div>
          <button 
            (click)="onRequestToken()"
            [disabled]="isRecoveryLoading"
            class="w-full py-2.5 bg-slate-900 hover:bg-slate-800 text-white font-bold text-xs uppercase tracking-widest transition-colors rounded-none disabled:opacity-50">
            {{ isRecoveryLoading ? 'Solicitando...' : 'Enviar Código' }}
          </button>
        </div>

        <!-- STEP 2: Enter code and new password -->
        <div *ngIf="recoveryStep === 2" class="space-y-4">
          <p class="text-xs text-slate-500 leading-relaxed">
            Introduce el código temporal que has recibido por correo y escribe tu nueva contraseña.
          </p>
          <div>
            <label class="block font-label text-[10px] font-bold text-slate-700 mb-1.5 uppercase tracking-widest">Código de Recuperación</label>
            <input 
              [(ngModel)]="recoveryToken" 
              type="text" 
              class="w-full px-3 py-2 border border-slate-300 bg-white text-slate-900 text-xs rounded-none focus:outline-none focus:ring-1 focus:ring-primary focus:border-primary font-mono text-center tracking-widest"
              placeholder="Ej. 123456">
          </div>
          <div>
            <label class="block font-label text-[10px] font-bold text-slate-700 mb-1.5 uppercase tracking-widest">Nueva Contraseña</label>
            <input 
              [(ngModel)]="recoveryNewPassword" 
              type="password" 
              class="w-full px-3 py-2 border border-slate-300 bg-white text-slate-900 text-xs rounded-none focus:outline-none focus:ring-1 focus:ring-primary focus:border-primary"
              placeholder="Mínimo 6 caracteres">
          </div>
          <button 
            (click)="onResetPassword()"
            [disabled]="isRecoveryLoading"
            class="w-full py-2.5 bg-slate-900 hover:bg-slate-800 text-white font-bold text-xs uppercase tracking-widest transition-colors rounded-none disabled:opacity-50">
            {{ isRecoveryLoading ? 'Restableciendo...' : 'Restablecer Contraseña' }}
          </button>
        </div>
      </div>
    </div>
  </div>
</main>
